        return CountdownIterator(self.start)

class CountdownIterator:
    def __init__(self, current: int):
        self.current = current

    def __iter__(self):
        return self  # Iterators return themselves

    def __next__(self) -> int:
        if self.current <= 0:
            raise StopIteration
        value = self.current
        self.current -= 1
        return value

