from abc import ABC, abstractmethod

class DataPipeline(ABC):
    """Template: extract -> transform -> load."""

    def run(self) -> dict:
        """Template method - defines the algorithm skeleton."""
        raw_data = self.extract()
        cleaned = self.transform(raw_data)
        result = self.load(cleaned)
        self.notify(result)  # Optional hook with default
        return result

    @abstractmethod
    def extract(self) -> list:
        """Step 1: Extract data from source."""
        ...

    @abstractmethod
    def transform(self, data: list) -> list:
        """Step 2: Transform/clean data."""
        ...

    @abstractmethod
    def load(self, data: list) -> dict:
        """Step 3: Load data to destination."""
        ...

    def notify(self, result: dict) -> None:
        """Optional hook (not abstract, has default)."""
        print(f"Pipeline complete: {result.get('count', 0)} records")

class CSVToDatabase(DataPipeline):
    def extract(self) -> list:
        print("Reading CSV file...")
        return [{'name': 'Alice', 'age': '30'}, {'name': 'Bob', 'age': '25'}]

    def transform(self, data: list) -> list:
        print("Converting ages to int...")
        return [{'name': d['name'], 'age': int(d['age'])} for d in data]

    def load(self, data: list) -> dict:
        print(f"Inserting {len(data)} records into database...")
        return {'count': len(data), 'status': 'success'}

class APIToFile(DataPipeline):
    def extract(self) -> list:
        print("Fetching from API...")
        return [{'id': 1, 'value': 'data'}]

    def transform(self, data: list) -> list:
        print("Formatting for file...")
        return [f"{d['id']},{d['value']}" for d in data]

    def load(self, data: list) -> dict:
        print(f"Writing {len(data)} lines to file...")
        return {'count': len(data), 'status': 'success'}

    def notify(self, result: dict) -> None:
        print(f"Sending Slack notification: {result}")

