# Real subject (expensive)
class RealDatabase:
    def __init__(self, connection_string: str):
        print(f"Connecting to {connection_string}...")
        time.sleep(0.1)  # Simulate slow connection
        self._conn = connection_string

    def query(self, sql: str) -> list:
        print(f"Executing: {sql}")
        return [{'id': 1, 'name': 'Alice'}]

# Virtual proxy (lazy loading)
class LazyDatabase:
    def __init__(self, connection_string: str):
        self._connection_string = connection_string
        self._db: RealDatabase | None = None

    def _get_db(self) -> RealDatabase:
        if self._db is None:
            self._db = RealDatabase(self._connection_string)
        return self._db

    def query(self, sql: str) -> list:
        return self._get_db().query(sql)

# No connection made yet
db = LazyDatabase('postgres://...')
print("DB object created, no connection yet")
# Connection made on first query
