# Caching proxy
class CachingDatabase:
    def __init__(self, db: Database):
        self._db = db
        self._cache: dict[str, list] = {}

    def query(self, sql: str) -> list:
        if sql in self._cache:
            print(f"Cache hit: {sql}")
            return self._cache[sql]
        print(f"Cache miss: {sql}")
        result = self._db.query(sql)
        self._cache[sql] = result
        return result

    def invalidate(self, sql: str | None = None) -> None:
        if sql:
            self._cache.pop(sql, None)
        else:
            self._cache.clear()

# Protection proxy
class ProtectedDatabase:
    def __init__(self, db: Database, allowed_users: set[str]):
        self._db = db
        self._allowed = allowed_users
        self._current_user: str | None = None

    def login(self, username: str) -> None:
        self._current_user = username

    def query(self, sql: str) -> list:
        if self._current_user not in self._allowed:
            raise PermissionError(f"User '{self._current_user}' not authorized")
        return self._db.query(sql)

# Stack proxies
real_db = RealDatabase('postgres://...')
cached = CachingDatabase(real_db)
protected = ProtectedDatabase(cached, {'admin', 'analyst'})

protected.login('admin')
result = protected.query('SELECT * FROM users')  # Cache miss
result = protected.query('SELECT * FROM users')  # Cache hit

