from abc import ABC, abstractmethod

# State interface
class OrderState(ABC):
    @abstractmethod
    def process(self, order: 'Order') -> str: ...
    @abstractmethod
    def cancel(self, order: 'Order') -> str: ...
    @abstractmethod
    def ship(self, order: 'Order') -> str: ...

# Concrete states
class PendingState(OrderState):
    def process(self, order: 'Order') -> str:
        order.state = ProcessingState()
        return "Order is now being processed"

    def cancel(self, order: 'Order') -> str:
        order.state = CancelledState()
        return "Order cancelled"

    def ship(self, order: 'Order') -> str:
        return "Cannot ship: order is not yet processed"

class ProcessingState(OrderState):
    def process(self, order: 'Order') -> str:
        return "Order is already being processed"

    def cancel(self, order: 'Order') -> str:
        order.state = CancelledState()
        return "Order cancelled during processing"

    def ship(self, order: 'Order') -> str:
        order.state = ShippedState()
        return "Order has been shipped!"

class ShippedState(OrderState):
    def process(self, order: 'Order') -> str:
        return "Cannot process: order already shipped"

    def cancel(self, order: 'Order') -> str:
        return "Cannot cancel: order already shipped"

    def ship(self, order: 'Order') -> str:
        return "Order is already shipped"

class CancelledState(OrderState):
    def process(self, order: 'Order') -> str:
        return "Cannot process: order is cancelled"

    def cancel(self, order: 'Order') -> str:
        return "Order is already cancelled"

    def ship(self, order: 'Order') -> str:
        return "Cannot ship: order is cancelled"

# Context
class Order:
    def __init__(self, order_id: int):
        self.order_id = order_id
        self.state: OrderState = PendingState()

    def process(self) -> str:
        return self.state.process(self)

    def cancel(self) -> str:
        return self.state.cancel(self)

    def ship(self) -> str:
        return self.state.ship(self)

    @property
    def status(self) -> str:
        return type(self.state).__name__.replace('State', '')

# Usage
order = Order(1)
print(order.status)      # Pending
print(order.ship())      # Cannot ship: order is not yet processed
print(order.process())   # Order is now being processed
print(order.status)      # Processing
print(order.ship())      # Order has been shipped!
print(order.status)      # Shipped
print(order.cancel())    # Cannot cancel: order already shipped

class PendingState:
    def process(self, order):
        order.state = ProcessingState()
        return "Processing"
    def cancel(self, order):
        order.state = CancelledState()
        return "Cancelled"

class Order:
    def __init__(self):
        self.state = PendingState()
    def process(self):
        return self.state.process(self)

