from typing import Any

# Abstract handler
class Handler(ABC):
    def __init__(self):
        self._next: Handler | None = None

    def set_next(self, handler: 'Handler') -> 'Handler':
        self._next = handler
        return handler  # For chaining: a.set_next(b).set_next(c)

    def handle(self, request: dict) -> str | None:
        if self._next:
            return self._next.handle(request)
        return None

# Concrete handlers
class AuthHandler(Handler):
    def handle(self, request: dict) -> str | None:
        if 'token' not in request:
            return "Error: Authentication required"
        print("Auth: Token verified")
        return super().handle(request)

class RateLimitHandler(Handler):
    def __init__(self, max_requests: int = 10):
        super().__init__()
        self._count = 0
        self._max = max_requests

    def handle(self, request: dict) -> str | None:
        self._count += 1
        if self._count > self._max:
            return "Error: Rate limit exceeded"
        print(f"RateLimit: {self._count}/{self._max}")
        return super().handle(request)

class ValidationHandler(Handler):
    def handle(self, request: dict) -> str | None:
        if 'body' not in request or not request['body']:
            return "Error: Request body is required"
        print("Validation: Body present")
        return super().handle(request)

class BusinessLogicHandler(Handler):
    def handle(self, request: dict) -> str | None:
        print(f"Processing: {request['body']}")
        return f"Success: Processed '{request['body']}'"

# Build the chain
auth = AuthHandler()
rate_limit = RateLimitHandler(max_requests=5)
validation = ValidationHandler()
logic = BusinessLogicHandler()

auth.set_next(rate_limit).set_next(validation).set_next(logic)

# Process requests through the chain
result = auth.handle({'token': 'abc', 'body': 'Hello'})
print(result)
# Auth: Token verified
# RateLimit: 1/5
# Validation: Body present
# Processing: Hello
# Success: Processed 'Hello'

# Missing token
result = auth.handle({'body': 'Hello'})
print(result)  # Error: Authentication required

# Pythonic: function-based chain (middleware pattern)
def create_chain(*handlers):
    def chain(request):
        for handler in handlers:
            result = handler(request)
            if result is not None:  # Handler consumed the request
                return result
        return None
    return chain

def check_auth(request):
    if 'token' not in request:
        return "Error: No token"
    return None  # Pass to next

def check_body(request):
    if 'body' not in request:
        return "Error: No body"
    return None

def process(request):
    return f"OK: {request['body']}"

pipeline = create_chain(check_auth, check_body, process)
print(pipeline({'token': 'x', 'body': 'data'}))  # OK: data

