from typing import Callable, Any
import functools
import time

# Strategy: text processing
def uppercase(text: str) -> str:
    return text.upper()

def reverse(text: str) -> str:
    return text[::-1]

def censor(text: str) -> str:
    bad_words = {'bad', 'ugly'}
    words = text.split()
    return ' '.join('***' if w.lower() in bad_words else w for w in words)

# Decorator wrappers (cross-cutting concerns)
def with_logging(func: Callable[[str], str]) -> Callable[[str], str]:
    @functools.wraps(func)
    def wrapper(text: str) -> str:
        print(f"[LOG] Input: {text!r}")
        result = func(text)
        print(f"[LOG] Output: {result!r}")
        return result
    return wrapper

def with_timing(func: Callable[[str], str]) -> Callable[[str], str]:
    @functools.wraps(func)
    def wrapper(text: str) -> str:
        start = time.time()
        result = func(text)
        print(f"[TIME] {func.__name__}: {time.time()-start:.4f}s")
        return result
    return wrapper

def with_strip(func: Callable[[str], str]) -> Callable[[str], str]:
    @functools.wraps(func)
    def wrapper(text: str) -> str:
        return func(text.strip())
    return wrapper

# Compose: strategy + decorators
pipeline = with_logging(with_timing(with_strip(uppercase)))
result = pipeline("  hello world  ")
# [LOG] Input: '  hello world  '
# [TIME] uppercase: 0.0000s
# [LOG] Output: 'HELLO WORLD'

# Pipeline builder
class Pipeline:
    def __init__(self):
        self._steps: list[Callable[[str], str]] = []

    def add_step(self, step: Callable[[str], str]) -> 'Pipeline':
        self._steps.append(step)
        return self

    def execute(self, data: str) -> str:
        result = data
        for step in self._steps:
            result = step(result)
        return result

pipeline = (
    Pipeline()
    .add_step(str.strip)
    .add_step(censor)
    .add_step(uppercase)
    .add_step(reverse)
)

result = pipeline.execute("  This is a bad example  ")
print(result)  # ELPMAXE *** A SI SIHT

