        return 2 * 3.14159 * self.radius

# Composition with mixins (combine behaviors)
class Serializable:
    def to_json(self) -> str:
        import json
        return json.dumps(self.__dict__)

class Validatable:
    def validate(self) -> bool:
        return all(v is not None for v in self.__dict__.values())

